class Solution:
    def countSmaller(self, nums):
        n = len(nums)
        res = [0] * n
        for i in range(n):
            c = 0
            for j in range(i + 1, n):
                if nums[j] < nums[i]:
                    c += 1
            res[i] = c
        return res

