var countSmaller = function(nums) {
    const n = nums.length;
    const res = new Array(n).fill(0);
    let idx = Array.from({ length: n }, (_, i) => i);
    const sort = (lo, hi) => {
        if (hi - lo <= 1) return;
        const mid = (lo + hi) >> 1;
        sort(lo, mid);
        sort(mid, hi);
        const merged = [];
        let i = lo, j = mid, rightDone = 0;
        while (i < mid && j < hi) {
            if (nums[idx[j]] < nums[idx[i]]) {
                rightDone++;
                merged.push(idx[j]);
                j++;
            } else {
                res[idx[i]] += rightDone;
                merged.push(idx[i]);
                i++;
            }
        }
        while (i < mid) {
            res[idx[i]] += rightDone;
            merged.push(idx[i]);
            i++;
        }
        while (j < hi) {
            merged.push(idx[j]);
            j++;
        }
        for (let p = 0; p < merged.length; p++) idx[lo + p] = merged[p];
    };
    sort(0, n);
    return res;
};
